import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

const fmt = (d) => d ? new Date(d).toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}) : "";

const STATUS = {
  accepted: { bg:"#dcfce7", color:"#15803d", border:"#86efac", icon:"✅" },
  rejected: { bg:"#fee2e2", color:"#dc2626", border:"#fca5a5", icon:"❌" },
  pending:  { bg:"#fef9c3", color:"#a16207", border:"#fde047", icon:"⏳" },
};

export default function MyProposals() {
  const navigate = useNavigate();
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get("/proposals/my")
      .then(r => { setProposals(r.data||[]); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return <div style={{ background:"#f8fafc", minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center" }}><span style={{ color:"#0f766e", fontWeight:"600" }}>Loading...</span></div>;

  return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" }}>
      <h1 style={{ fontSize:"24px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>My Proposals</h1>
      <p style={{ color:"#64748b", fontSize:"13px", marginBottom:"28px" }}>Track all proposals you have submitted</p>

      {proposals.length === 0 ? (
        <div style={{ background:"white", borderRadius:"14px", padding:"60px", textAlign:"center", border:"1px solid #e2e8f0" }}>
          <div style={{ fontSize:"40px", marginBottom:"12px" }}>📄</div>
          <p style={{ color:"#94a3b8", marginBottom:"12px" }}>No proposals yet.</p>
          <button onClick={() => navigate("/freelancer/find-projects")}
            style={{ padding:"9px 20px", borderRadius:"8px", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontSize:"13px", fontWeight:"700", cursor:"pointer" }}>
            Find Projects →
          </button>
        </div>
      ) : proposals.map(p => {
        const s = STATUS[p.status] || STATUS.pending;
        return (
          <div key={p.id} style={{ background:"white", border:"1px solid #e2e8f0", borderLeft:`4px solid ${s.color}`, borderRadius:"12px", padding:"20px", marginBottom:"12px", boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"10px" }}>
              <div>
                <h3 style={{ fontSize:"15px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>{p.project_title}</h3>
                <p style={{ fontSize:"13px", color:"#64748b", margin:0, lineHeight:1.5 }}>{p.message}</p>
              </div>
              <span style={{ background:s.bg, color:s.color, border:`1px solid ${s.border}`, fontSize:"11px", fontWeight:"700", padding:"4px 12px", borderRadius:"20px", flexShrink:0, marginLeft:"12px", textTransform:"capitalize" }}>
                {s.icon} {p.status || "pending"}
              </span>
            </div>
            <div style={{ display:"flex", gap:"18px", fontSize:"12px", color:"#94a3b8", paddingTop:"10px", borderTop:"1px solid #f1f5f9" }}>
              <span>Your Bid: <strong style={{ color:"#0f766e" }}>₹{p.bid}</strong></span>
              {p.project_budget && <span>Budget: ₹{p.project_budget}</span>}
              {p.created_at && <span>📅 {fmt(p.created_at)}</span>}
              {p.project_deadline && <span>Due: {fmt(p.project_deadline)}</span>}
            </div>
          </div>
        );
      })}
    </div>
  );
}
